public class PetIntegrationTest extends com.swaggerpetstore.base.BaseTest {

    private PetApiClient client;

    @BeforeEach
    void initClient() {
        client = new PetApiClient(requestSpec);
    }

    @Test
    void createPet_thenGetById_success() {
        PetInputDto pet = PetInputDto.builder()
                .id(100500)
                .name("integrationDog")
                .photoUrls(List.of("http://example.com/dog.jpg"))
                .status("available")
                .build();

        Response createResponse = client.create(pet);
        createResponse.then().statusCode(200);

        long petId = createResponse.jsonPath().getLong("id");

        Response getResponse = client.getById(petId);
        getResponse.then()
