        PetInputDto pet = PetInputDto.builder()
                .id(100501)
                .name("updateDog")
                .photoUrls(List.of("http://example.com/dog2.jpg"))
                .status("available")
                .build();

        client.create(pet).then().statusCode(200);

        PetInputDto updatedPet = PetInputDto.builder()
                .id(100501)
                .name("updatedDogName")
                .photoUrls(List.of("http://example.com/dog2.jpg"))
                .status("pending")
                .build();

        Response updateResponse = client.update(100501L, updatedPet);
        updateResponse.then()
                .statusCode(200)
                .body("name", org.hamcrest.Matchers.equalTo("updatedDogName"))
                .body("status", org.hamcrest.Matchers.equalTo("pending"));
    }

    @Test
    void deletePet_success() {
        PetInputDto pet = PetInputDto.builder()
                .id(100502)
                .name("deleteDog")
                .photoUrls(List.of("http://example.com/dog3.jpg"))
                .status("available")
                .build();

        client.create(pet).then().statusCode(200);

        Response deleteResponse = client.delete(100502);
        deleteResponse.then().statusCode(200);
    }
}

